package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_defaultFalse() {
        CSVFormat format = new CSVFormat(
                ',',
                null,
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                null,
                false,
                false,
                false,
                false,
                false,
                false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_trueValue() {
        CSVFormat format = new CSVFormat(
                ',',
                null,
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                null,
                false,
                false,
                true,
                false,
                false,
                false);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_falseValue() {
        CSVFormat format = new CSVFormat(
                ',',
                null,
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                null,
                false,
                false,
                false,
                false,
                false,
                false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_withIgnoreHeaderCaseMethod() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());

        CSVFormat format2 = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format2.getIgnoreHeaderCase());
    }

}
